```python
import os
import json
from core.config.config import DEFAULT_OUTPUT_DIR
from core.config.config_manager import get_config

class SuperFormatter:
    @staticmethod
    def render(value, target="IA", meta=None, destination=None, path=None):
        config = get_config()
        meta = meta or {}
        output_rules = meta.get("output_format", {})
        default_format = output_rules.get("default", config.get("default_output_format", "json_nested"))
        allowed = output_rules.get("allowed", ["json_nested", "flat_list", "string", "markdown"])
        forbidden = output_rules.get("forbidden", [])

        # Détection du format à utiliser
        format_type = default_format
        if format_type in forbidden:
            format_type = "string"

        # Formatage du contenu
        if format_type == "json_nested":
            formatted = value
        elif format_type == "flat_list":
            formatted = SuperFormatter._to_flat_list(value)
        elif format_type == "string":
            formatted = SuperFormatter._to_string(value)
        elif format_type == "markdown":
            formatted = SuperFormatter._to_markdown(value)
        else:
            formatted = value

        # Détection du mode de sortie
        if destination not in ["return", "stdout", "file"]:
            destination = config.get("default_output_destination", "file")

        if destination == "file":
            if not path:
                subdir = meta.get("context", config.get("default_output_context", "queries"))
                full_dir = os.path.join(DEFAULT_OUTPUT_DIR, subdir)
                os.makedirs(full_dir, exist_ok=True)
                path = os.path.join(full_dir, f"output_{format_type}.txt")

            with open(path, "w", encoding="utf-8") as f:
                if isinstance(formatted, (dict, list)):
                    f.write(json.dumps(formatted, indent=2, ensure_ascii=False))
                else:
                    f.write(str(formatted))
            return path

        elif destination == "stdout":
            print(formatted)

        return formatted

    @staticmethod
    def _to_flat_list(value):
        if not isinstance(value, list):
            return [{"value": value}]
        return [
            {
                "type": node.get("type"),
                "name": node.get("name"),
                "path": node.get("prefix", "") + node.get("name", "")
            }
            for node in value
        ]

    @staticmethod
    def _to_string(value):
        if isinstance(value, list):
            return "\n".join([v.get("prefix", "") + v.get("name", "") for v in value])
        return str(value)

    @staticmethod
    def _to_markdown(value):
        if isinstance(value, list):
            return "\n".join(["- " + v.get("prefix", "") + "**" + v.get("name", "") + "**" for v in value])
        return f"`{str(value)}`"
